import React, { useEffect, useState } from "react";
import { Link, useNavigate } from 'react-router-dom';
import DataTable from "react-data-table-component";
import alertPopUp from 'sweetalert2';
import withReactContent from 'sweetalert2-react-content';
import { deleteModalSwal, epochTogmt } from "../../../utils/Common";
import { CButton, CFormLabel } from "@coreui/react";
import { deleteJobPosition, deletePosition, fetchAllJobPositionData } from "../../../components/services/CareerApi";
import { tableJobPositionConstant } from "./tableJobPositionConstant";
import { customStyles } from "../../../utils/tableCustomStyles";
import ExportCSV from "../../../utils/ExportCsvButton";
import authService from "src/auth/auth.service";

const MySwal = withReactContent(alertPopUp);

const headers = [
    { label: "Position Title", key: "title" },
    { label: "Department", key: "department" },
    { label: "Status", key: "status" },
    { label: "Created Date", key: "createTime" },
];

function listPosition() {
    const [rowData, setRowData] = useState([]);

    useEffect(() => {
        fetchJobPositionList();
    }, []);

    const fetchJobPositionList = async () =>{
        let response = await fetchAllJobPositionData();
        let data = [];
        if(response?.code === 200){
            response?.results && response?.results.map((item) => {
                item.createTime = epochTogmt(item.createTime);
                data.push(item);
            })
            setRowData(data);
        }
    }

    const handleDelete = async (id) => {
        const response = await deleteJobPosition(id);
        if(response?.code === 200) {
            fetchJobPositionList();
        }
    }

    const handleConfirmModal = (id) => {
        const handleConfirm = async () => {
            const swalval = await MySwal.fire(deleteModalSwal);
            if (swalval && swalval.value === true) {
                handleDelete(id)
            }
        };
        handleConfirm();
    };

    const actionButton = () => {
        return (
            <React.Fragment>
               {authService.getPermission("POSITION_EXPORT_CSV") && rowData.length > 0 && <ExportCSV headers={headers} data={rowData} filename="position_list" />}
            </React.Fragment>
        );
    };

    const handleSelectChange = (data) => {
        setJobType(data)
        // fetchJobPositionList(data?.value);
    }

    return (<div className='row'>
        <div className="col2Large">
            <DataTable
                title="Position"
                columns={tableJobPositionConstant(fetchJobPositionList, handleConfirmModal)}
                data={rowData}
                customStyles={customStyles}
                actions={actionButton()}
                pagination
                paginationPerPage={10}
                pointerOnHover
                fixedHeader
                noContextMenu
                fixedHeaderScrollHeight={"calc(100vh - 226px)"}
            />
        </div>
       {authService.getPermission("CAREER_POSITION_CREATE") && <div className='col-sm-12'>
            <Link to={"/career/position/create"}>
                <CButton type="submit" color="primary" className="create-btn" style={{ float: "right" }}>
                    {"+ Create Position"}
                </CButton>
            </Link>
        </div>}
    </div>)
}

export default listPosition
